    volumes:
      - rallly-minio:/data

  minio-init:
    image: minio/mc:latest
    depends_on:
      - minio
    restart: "no"
    entrypoint: >
      /bin/sh -c "
      until mc alias set local http://minio:9000 ${S3_ACCESS_KEY_ID} ${S3_SECRET_ACCESS_KEY}; do sleep 2; done;
      mc mb --ignore-existing local/rallly;
      "

volumes:
  rallly-db:
  rallly-minio:

